const i=document.querySelectorAll(".book-img-mini");i.forEach(e=>{e.addEventListener("click",()=>l(e))});function l(e){if(!e.classList.contains("opened-preview")){let o=document.querySelectorAll(".book-img-mini"),t=document.querySelector(".book-cover"),r=t.src;o.forEach(c=>{c.src==r&&c.classList.toggle("opened-preview"),t.src=e.src,e.classList.add("opened-preview")})}}document.querySelector(".qty-count--minus").addEventListener("click",()=>{let e=document.querySelector(".product-qty");e.value>1&&e.value--});document.querySelector(".qty-count--add").addEventListener("click",()=>{let e=document.querySelector(".product-qty");e.value++});
